import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import { ArrowUpward, ArrowDownward } from '@mui/icons-material';
import response from './response.json';

interface LoyaltyData {
  balance: {
    currentPoints: number;
    tier: string;
  };
  recentTransactions: {
    date: string;
    description: string;
    points: number;
  }[];
  rewardsAvailable: {
    name: string;
    pointsRequired: number;
  }[];
}

export default function Widget() {
  const loyaltyData = response.data as LoyaltyData;
  const { balance, recentTransactions, rewardsAvailable } = loyaltyData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Loyalty Points Balance
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ color: '#FF5722' }}>
              {balance.currentPoints}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              Tier: {balance.tier}
            </Typography>
          </Box>

          <Divider sx={{ my: 1 }} />

          <Typography variant="body2" fontWeight={500} sx={{ mb: 1 }}>
            Recent Transactions
          </Typography>
          <Stack spacing={0.5}>
            {recentTransactions.slice(0, 3).map((transaction, index) => (
              <Box key={index} display="flex" justifyContent="space-between">
                <Box>
                  <Typography variant="body2">{transaction.description}</Typography>
                  <Typography variant="caption" color="text.secondary">
                    {transaction.date}
                  </Typography>
                </Box>
                <Box display="flex" alignItems="center">
                  {transaction.points > 0 ? (
                    <ArrowUpward fontSize="small" sx={{ color: '#10B981' }} />
                  ) : (
                    <ArrowDownward fontSize="small" sx={{ color: '#EF4444' }} />
                  )}
                  <Typography variant="body2" fontWeight={600} sx={{ ml: 0.5 }}>
                    {transaction.points}
                  </Typography>
                </Box>
              </Box>
            ))}
          </Stack>

          <Divider sx={{ my: 1 }} />

          <Typography variant="body2" fontWeight={500} sx={{ mb: 1 }}>
            Rewards Available
          </Typography>
          <Stack direction="row" spacing={0.5}>
            {rewardsAvailable.slice(0, 3).map((reward, index) => (
              <Chip
                key={index}
                label={`${reward.name} (${reward.pointsRequired} pts)`}
                sx={{ fontSize: '11px', px: 1, py: 0.5 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
